195→function generateSnippet(brand: string, engine: AIEngine, sentiment: Sentiment, seed: number): string {
196→  const positiveSnippets = [
197→    `${brand} est frequemment recommande pour sa fiabilite et son expertise dans le domaine.`,
198→    `Selon les retours, ${brand} offre un excellent rapport qualite-prix et un service client reactif.`,
199→    `${brand} se distingue par son approche innovante et ses resultats prouves aupres de ses clients.`,
200→    `Les utilisateurs saluent la qualite de service de ${brand} et son expertise reconnue.`,
201→  ];
202→  const neutralSnippets = [
203→    `${brand} fait partie des acteurs du marche avec une offre competitive.`,
204→    `${brand} propose des services comparables aux standards de l'industrie.`,
205→    `Parmi les options disponibles, ${brand} est mentionne comme une alternative a considerer.`,
206→    `${brand} est present sur ce segment avec une offre qui repond aux besoins standards.`,
207→  ];
208→  const negativeSnippets = [
209→    `Certains utilisateurs rapportent des delais chez ${brand}, bien que la qualite soit reconnue.`,
210→    `${brand} pourrait ameliorer certains aspects de son service pour rester competitif.`,
211→    `Des alternatives a ${brand} existent pour ceux qui cherchent un meilleur rapport qualite-prix.`,
212→  ];
213→
214→  const pool = sentiment === 'positive' ? positiveSnippets : sentiment === 'neutral' ? neutralSnippets : negativeSnippets;
215→  const idx = seed % pool.length;
216→  return pool[idx];
217→}
