  3→// Animated counter hook
  4→const useCountUp = (target: number, duration = 1200) => {
  5→  const [count, setCount] = useState(0);
  6→  const ref = useRef<HTMLDivElement>(null);
  7→  useEffect(() => {
  8→    const observer = new IntersectionObserver(([entry]) => {
  9→      if (entry.isIntersecting) {
 10→        let start = 0;
 11→        const startTime = performance.now();
 12→        const step = (now: number) => {
 13→          const progress = Math.min((now - startTime) / duration, 1);
 14→          const eased = 1 - Math.pow(1 - progress, 3); // ease-out cubic
 15→          setCount(Math.round(eased * target));
 16→          if (progress < 1) requestAnimationFrame(step);
 17→        };
 18→        requestAnimationFrame(step);
 19→        observer.disconnect();
 20→      }
 21→    }, { threshold: 0.3 });
 22→    if (ref.current) observer.observe(ref.current);
 23→    return () => observer.disconnect();
 24→  }, [target, duration]);
 25→  return { count, ref };
 26→};
